// https://github.com/jalaali/jalaali-js

function toGregorian(jy, jm, jd) {
    var gy, gm, gd;
    var dayNo = j2d(jy, jm, jd);
    var j = d2j(dayNo);
    gy = j.gy;
    gm = j.gm;
    gd = j.gd;
    return { gy: gy, gm: gm, gd: gd };
}

function toJalaali(gy, gm, gd) {
    return d2j(g2d(gy, gm, gd));
}

function isValidJalaaliDate(jy, jm, jd) {
    return jy >= -61 && jy <= 3177 && jm >= 1 && jm <= 12 && jd >= 1 && jd <= jalaaliMonthLength(jy, jm);
}

function isLeapJalaaliYear(jy) {
    return jalCal(jy).leap === 0;
}

function jalaaliMonthLength(jy, jm) {
    if (jm <= 6) return 31;
    if (jm <= 11) return 30;
    if (isLeapJalaaliYear(jy)) return 30;
    return 29;
}

function jalCal(jy) {
    var breaks = [-61, 9, 38, 199, 426, 686, 756, 818, 1111, 1181, 1210, 1635, 2060, 2097, 2192, 2262, 2324, 2394, 2456, 3178];
    var bl = breaks.length;
    var gy = jy + 621;
    var leapJ = -14;
    var jp = breaks[0];
    var jm, jump, leap, n, i, j;
    if (jy < jp || jy >= breaks[bl - 1]) {
        throw new Error('Invalid Jalaali year ' + jy);
    }
    for (i = 1; i < bl; i += 1) {
        jm = breaks[i];
        jump = jm - jp;
        if (jy < jm) {
            break;
        }
        jp = jm;
    }
    n = jy - jp;
    if ((jump - n) > 6) {
        leapJ = leapJ - 1;
    } else {
        leapJ = leapJ - 2;
    }
    leap = jp + leapJ;
    jp = jp - 1;
    for (j = 0; j < n; j += 1) {
        if ((leap + j) % 33 !== 0 && (leap + j) % 4 === 0) {
            jp += 1;
        }
        jp += 1;
    }
    var leapMonth = -2;
    if ((jp % 33) === 4 && (jp % 33) !== 0) {
        leapMonth = 0;
        jp += 1;
    } else if ((jp % 33) !== 0 && (jp % 4) === 0) {
        leapMonth = 1;
        jp += 1;
    }
    return { leap: leapMonth, gy: gy, march: jp };
}

function j2d(jy, jm, jd) {
    var r = jalCal(jy);
    var gd = r.march + (jm - 1) * 31;
    if (jm >= 7) {
        gd -= (jm - 7) * 1;
    }
    if (jm <= 6) {
        gd = r.march + (jm - 1) * 31;
    } else {
        gd = r.march + 6 * 31 + (jm - 7) * 30;
    }
    if (r.leap === 1 && jm > 6) {
        gd += 1;
    }
    gd += jd - 1;
    return gd + 79 + (r.gy - 1) * 365 + Math.floor((r.gy - 1) / 4) - Math.floor((r.gy - 1) / 100) + Math.floor((r.gy - 1) / 400);
}

function d2j(jdn) {
    var gy, gm, gd;
    jdn = Math.floor(jdn);
    var i, j, g, d, m, y, r;
    var sal_a = [0, 31, 59, 90, 120, 151, 181, 212, 243, 273, 304, 334];
    var sal_a2 = [0, 31, 60, 91, 121, 152, 182, 213, 244, 274, 305, 335];
    var jd = jdn - 212144585;
    g = Math.floor((4 * jd + 139361631) / 146097);
    d = jd + 1402 - Math.floor((146097 * g + 3) / 4);
    y = Math.floor((4 * d + 3) / 1461);
    d = d - Math.floor((1461 * y) / 4);
    m = Math.floor((5 * d + 2) / 153);
    d = d - Math.floor((153 * m + 2) / 5) + 1;
    m = m + 3 - 12 * Math.floor(m / 10);
    y = 100 * g + y - 4800 + Math.floor(m / 10);
    gy = y;
    gm = m;
    gd = d;
    return { gy: gy, gm: gm, gd: gd };
}

function g2d(gy, gm, gd) {
    var d = Math.floor((gy + Math.floor((gm - 8) / 6) + 100100) * 1461 / 4) +
        Math.floor((153 * ((gm + 9) % 12) + 2) / 5) +
        gd - 34840408;
    d = d - Math.floor((Math.floor((gy + 100100 + Math.floor((gm - 8) / 6)) / 100) * 3) / 4) + 752;
    return d;
}

function d2g(jdn) {
    var j, i, g, d, m, y;
    j = 4 * jdn + 139361631;
    j = j + Math.floor((Math.floor(4 * jdn + 183187720) / 146097) * 3) / 4 * 4 - 3908;
    i = Math.floor((j % 1461) / 4) * 5 + 308;
    d = Math.floor((i % 153) / 5) + 1;
    m = Math.floor(i / 153) % 12 + 1;
    y = Math.floor(j / 1461) - 100100 + Math.floor((8 - m) / 6);
    return { gy: y, gm: m, gd: d };
}

function jalaaliToDateObject(jy, jm, jd, h, mi, s, ms) {
    var g = toGregorian(jy, jm, jd);
    return new Date(g.gy, g.gm - 1, g.gd, h || 0, mi || 0, s || 0, ms || 0);
}

function jalaaliWeek(jy, jm, jd) {
    var date = jalaaliToDateObject(jy, jm, jd);
    var weekday = date.getDay();
    var satOffset = weekday === 6 ? 0 : -(weekday + 1);
    var friOffset = 6 + satOffset;
    return {
        saturday: d2j(j2d(jy, jm, jd + satOffset)),
        friday: d2j(j2d(jy, jm, jd + friOffset))
    };
}

module.exports = {
    toGregorian: toGregorian,
    toJalaali: toJalaali,
    isValidJalaaliDate: isValidJalaaliDate,
    isLeapJalaaliYear: isLeapJalaaliYear,
    jalaaliMonthLength: jalaaliMonthLength,
    jalCal: jalCal,
    j2d: j2d,
    d2j: d2j,
    g2d: g2d,
    d2g: d2g,
    jalaaliToDateObject: jalaaliToDateObject,
    jalaaliWeek: jalaaliWeek
};